+/** Debounce fn by `wait` ms. Trailing-edge. Returns a callable with .cancel()/.flush(). */
+export function debounce<A extends unknown[]>(fn: (...a: A) => void, wait: number) {
+  let timer: ReturnType<typeof setTimeout> | null = null;
+  let lastArgs: A | null = null;
+  const debounced = (...args: A): void => {
+    lastArgs = args;
+    if (timer) clearTimeout(timer);
+    timer = setTimeout(() => { timer = null; const a = lastArgs!; lastArgs = null; fn(...a); }, wait);
+  };
+  debounced.cancel = (): void => { if (timer) { clearTimeout(timer); timer = null; lastArgs = null; } };
+  debounced.flush = (): void => { if (timer && lastArgs) { clearTimeout(timer); timer = null; const a = lastArgs; lastArgs = null; fn(...a); } };
+  return debounced;
+}
